const binary = $binary ?? {};
const upload = binary.receipt;

if (!upload) {
  return [{
    json: {
      valid: false,
      statusCode: 400,
      body: {
        error_code: 'INVALID_INPUT',
        message: 'A receipt image is required in the multipart field \"receipt\".'
      }
    }
  }];
}

const mimeType = upload.mimeType ?? '';
if (!mimeType.startsWith('image/')) {
  return [{
    json: {
      valid: false,
      statusCode: 400,
      body: {
        error_code: 'INVALID_INPUT',
        message: 'Only image uploads are supported for receipt OCR.'
      }
    },
    binary
  }];
}

return [{
  json: {
    valid: true,
    binaryPropertyName: 'receipt'
  },
  binary
}];

const payload = $json ?? {};
const requiredConfidence = Number($env.OCR_REQUIRED_CONFIDENCE ?? '0.65');
const fallbackCurrency = String($env.OCR_DEFAULT_CURRENCY ?? 'VND').toUpperCase();

function normalizeDate(value) {
  if (!value) return null;
  if (/^\d{4}-\d{2}-\d{2}T/.test(value)) return value;
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return `${value}T00:00:00Z`;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
}

function mapCategory(sourceValues) {
  const source = sourceValues.filter(Boolean).join(' ').toLowerCase();
  if (/(coffee|restaurant|cafe|tea|food|drink|highlands|starbucks|pho|bun)/.test(source)) return 'Ăn uống';
  if (/(taxi|grab|uber|bus|train|flight|transport|parking)/.test(source)) return 'Di chuyển';
  if (/(electric|water|internet|utility|bill|phone)/.test(source)) return 'Hóa đơn';
  if (/(market|mart|store|shop|retail|supermarket)/.test(source)) return 'Mua sắm';
  return 'Khác';
}

function buildError(errorCode, message, details = undefined) {
  return [{
    json: {
      ok: false,
      statusCode: 400,
      body: {
        error_code: errorCode,
        message,
        ...(details ? { details } : {})
      }
    }
  }];
}

if (payload.error || payload.statusCode >= 400) {
  return buildError('OCR_FAILED', 'Veryfi OCR request failed before a usable extraction was returned.');
}

if (payload.blurry === true) {
  return buildError('BLURRY_IMAGE', 'The receipt image is too blurry for reliable OCR extraction.');
}

const totalAmount = Number(payload.total ?? payload.grand_total ?? payload.total_amount);
const currency = String(payload.currency_code ?? fallbackCurrency).toUpperCase();
const merchantName = String(payload.vendor?.name ?? payload.vendor_name ?? payload.vendor ?? '').trim();
const transactionDatetime = normalizeDate(payload.date ?? payload.transaction_date ?? payload.created_date);
const paymentMethod = String(payload.payment?.display_name ?? payload.payment?.type ?? payload.payment_method ?? 'Unknown').trim() || 'Unknown';
const suggestedCategory = mapCategory([
  payload.category,
  payload.line_items?.map((item) => item.description).join(' '),
  merchantName
]);

const confidenceValues = [];
const confidenceDetails = payload.confidence_details ?? {};
for (const key of ['total', 'vendor_name', 'date']) {
  const value = Number(confidenceDetails[key]);
  if (!Number.isNaN(value)) confidenceValues.push(value);
}
const lowestConfidence = confidenceValues.length ? Math.min(...confidenceValues) : 1;
if (lowestConfidence < requiredConfidence) {
  return buildError('BLURRY_IMAGE', 'The receipt image did not meet the configured OCR confidence threshold.', { lowest_confidence: lowestConfidence });
}

const missingFields = [];
if (!Number.isFinite(totalAmount)) missingFields.push('total_amount');
if (!currency) missingFields.push('currency');
if (!merchantName) missingFields.push('merchant_name');
if (!transactionDatetime) missingFields.push('transaction_datetime');
if (missingFields.length > 0) {
  return buildError('INSUFFICIENT_DATA', 'OCR completed but required receipt fields could not be derived reliably.', { missing_fields: missingFields });
}

return [{
  json: {
    ok: true,
    statusCode: 200,
    body: {
      total_amount: totalAmount,
      currency,
      transaction_datetime: transactionDatetime,
      merchant_name: merchantName,
      payment_method: paymentMethod,
      ai_suggested_category: suggestedCategory
    }
  }
}];
